import React, { useEffect, useState, useCallback } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import './AnalyticsPage.css';
import { Line, Bar } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend
);

const AnalyticsPage = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [data, setData] = useState(null);
  const [error, setError] = useState(null);
  const [monthFilter, setMonthFilter] = useState('');
  const [yearFilter, setYearFilter] = useState('');

  const API_BASE_URL = 'http://localhost:5001';

  const colors = {
    primary: '#6366f1',
    secondary: '#ec4899',
    success: '#10b981',
    warning: '#f59e0b',
    danger: '#ef4444',
    light: '#f3f4f6',
    dark: '#1f2937',
  };

  const formatCurrency = (value) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      minimumFractionDigits: 0,
    }).format(value);
  };

  const formatNumber = (value) => {
    return value.toLocaleString('en-IN');
  };

  const getNextMonth = () => {
    const currentDate = new Date();
    const nextMonth = new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1);
    const monthNames = ['January', 'February', 'March', 'April', 'May', 'June', 
                       'July', 'August', 'September', 'October', 'November', 'December'];
    return `${monthNames[nextMonth.getMonth()]} ${nextMonth.getFullYear()}`;
  };

  const fetchData = useCallback(async (endpoint) => {
    try {
      const response = await fetch(`${API_BASE_URL}${endpoint}`);
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}`);
      }
      return await response.json();
    } catch (error) {
      console.error(`Error fetching ${endpoint}:`, error);
      setError(`Failed to fetch data from ${endpoint}`);
      return null;
    }
  }, []);

  const loadDashboardData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      // Check API health first
      const health = await fetchData('/health');
      if (!health) {
        setError('Cannot connect to ML API. Make sure Flask is running on port 5001.');
        setLoading(false);
        return;
      }

      // Load all dashboard data from single endpoint
      const dashboardData = await fetchData('/api/dashboard-data');
      if (!dashboardData) {
        setError('Failed to load dashboard data');
        setLoading(false);
        return;
      }

      // Extract and organize data
      const monthlyData = dashboardData.monthly_revenue || [];
      const brandsData = dashboardData.top_brands || [];
      const predictedRevenue = dashboardData.predicted_revenue;
      const predictedSales = dashboardData.predicted_sales;

      const combinedData = {
        monthly_revenue: monthlyData,
        top_brands: brandsData,
        predicted_revenue: predictedRevenue,
        predicted_sales: predictedSales,
      };

      setData(combinedData);
    } catch (err) {
      console.error('Error loading dashboard data:', err);
      setError('Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  }, [fetchData]);

  useEffect(() => {
    if (user?.role !== 'admin') {
      navigate('/');
      return;
    }
    loadDashboardData();
  }, [user, navigate, loadDashboardData]);

  if (user?.role !== 'admin') {
    return null;
  }

  if (loading) {
    return (
      <div style={styles.container}>
        <div style={styles.loadingContainer}>
          <div style={styles.spinner}></div>
          <p>Loading AI Sales Insights...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div style={styles.container}>
        <div style={styles.errorAlert}>
          <h3>⚠️ Error</h3>
          <p>{error}</p>
          <button onClick={loadDashboardData} style={styles.retryBtn}>
            Retry
          </button>
        </div>
      </div>
    );
  }

  const monthlyData = data?.monthly_revenue || [];
  const brandsData = data?.top_brands || [];
  const totalRevenue = monthlyData.reduce((sum, d) => sum + (d.revenue || 0), 0);
  const totalSales = monthlyData.reduce((sum, d) => sum + (d.products || 0), 0);
  const topBrand = brandsData.length > 0 ? brandsData[0]?.brand : 'N/A';

  const revenueChartData = {
    labels: monthlyData.map((d) => d.month || ''),
    datasets: [
      {
        label: 'Monthly Revenue',
        data: monthlyData.map((d) => d.revenue || 0),
        borderColor: colors.primary,
        backgroundColor: `${colors.primary}20`,
        borderWidth: 3,
        fill: true,
        tension: 0.4,
        pointRadius: 6,
        pointBackgroundColor: colors.primary,
        pointBorderColor: '#fff',
        pointBorderWidth: 2,
      },
    ],
  };

  const salesChartData = {
    labels: monthlyData.map((d) => d.month || ''),
    datasets: [
      {
        label: 'Monthly Sales (Units)',
        data: monthlyData.map((d) => d.products || 0),
        borderColor: colors.secondary,
        backgroundColor: `${colors.secondary}20`,
        borderWidth: 3,
        fill: true,
        tension: 0.4,
        pointRadius: 6,
        pointBackgroundColor: colors.secondary,
        pointBorderColor: '#fff',
        pointBorderWidth: 2,
      },
    ],
  };

  const brandsChartData = {
    labels: brandsData.slice(0, 5).map((d) => d.brand || ''),
    datasets: [
      {
        label: 'Units Sold',
        data: brandsData.slice(0, 5).map((d) => d.quantity || 0),
        backgroundColor: [
          colors.primary,
          colors.secondary,
          colors.success,
          colors.warning,
          colors.danger,
        ],
        borderRadius: 8,
      },
    ],
  };

  const chartOptions = {
    responsive: true,
    maintainAspectRatio: true,
    plugins: {
      legend: {
        display: true,
        labels: { color: colors.dark, font: { size: 12 } },
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        ticks: { color: colors.dark },
        grid: { color: '#e5e7eb' },
      },
      x: {
        ticks: { color: colors.dark },
        grid: { color: '#e5e7eb' },
      },
    },
  };

  return (
    <div style={styles.container}>
      {/* Header */}
      <div style={styles.header}>
        <h1 style={styles.headerTitle}>🤖 AI Sales Insights</h1>
        <p style={styles.headerSubtitle}>
          Real-time insights and predictions powered by machine learning
        </p>
      </div>

      {/* Key Metrics Cards */}
      <div style={styles.metricsGrid}>
        <div style={styles.statCard}>
          <div style={{ ...styles.statIcon, backgroundColor: `${colors.primary}15`, color: colors.primary }}>
            💰
          </div>
          <div style={styles.statValue}>{formatCurrency(totalRevenue)}</div>
          <div style={styles.statLabel}>Predicted Revenue</div>
        </div>

        <div style={styles.statCard}>
          <div style={{ ...styles.statIcon, backgroundColor: `${colors.secondary}15`, color: colors.secondary }}>
            📦
          </div>
          <div style={styles.statValue}>{formatNumber(totalSales)}</div>
          <div style={styles.statLabel}>Total Units Sold</div>
        </div>

        <div style={styles.statCard}>
          <div style={{ ...styles.statIcon, backgroundColor: `${colors.success}15`, color: colors.success }}>
            ⭐
          </div>
          <div style={styles.statValue}>{topBrand}</div>
          <div style={styles.statLabel}>Top Brand</div>
        </div>
      </div>

      {/* Section: Monthly Analytics */}
      <h3 style={styles.sectionTitle}>📊 Monthly Analytics</h3>

      <div style={styles.chartsGrid}>
        {/* Revenue Chart */}
        <div style={styles.chartContainer}>
          <h5 style={styles.chartTitle}>Monthly Revenue Trend</h5>
          <div style={styles.chartWrapper}>
            <Line data={revenueChartData} options={chartOptions} />
          </div>
          <small style={styles.chartNote}>Total revenue per month | Scale: INR</small>
        </div>

        {/* Sales Chart */}
        <div style={styles.chartContainer}>
          <h5 style={styles.chartTitle}>Monthly Sales (Units)</h5>
          <div style={styles.chartWrapper}>
            <Line data={salesChartData} options={chartOptions} />
          </div>
          <small style={styles.chartNote}>Total products sold per month | Scale: Units</small>
        </div>
      </div>

      {/* Section: Brand Analysis */}
      <h3 style={styles.sectionTitle}>🏆 Top Brands Analysis</h3>

      <div style={styles.chartsGrid}>
        {/* Brands Chart */}
        <div style={styles.chartContainer}>
          <h5 style={styles.chartTitle}>Top 5 Brands by Sales</h5>
          <div style={styles.chartWrapper}>
            <Bar data={brandsChartData} options={chartOptions} />
          </div>
          <small style={styles.chartNote}>Sales volume comparison across brands</small>
        </div>

        {/* Brands Table */}
        <div style={styles.tableContainer}>
          <h5 style={styles.chartTitle}>Brand Breakdown</h5>
          <table style={styles.table}>
            <thead style={styles.tableHead}>
              <tr>
                <th style={styles.tableHeader}>Brand</th>
                <th style={styles.tableHeader}>Units Sold</th>
                <th style={styles.tableHeader}>Revenue</th>
              </tr>
            </thead>
            <tbody>
              {brandsData.slice(0, 5).map((brand, idx) => (
                <tr key={idx} style={styles.tableRow}>
                  <td style={styles.tableCell}>
                    <span
                      style={{
                        ...styles.badge,
                        backgroundColor: [
                          colors.primary,
                          colors.secondary,
                          colors.success,
                          colors.warning,
                          colors.danger,
                        ][idx % 5],
                      }}
                    >
                      {idx + 1}
                    </span>
                    {brand.brand}
                  </td>
                  <td style={styles.tableCell}>{formatNumber(brand.quantity || 0)}</td>
                  <td style={styles.tableCell}>{formatCurrency(brand.revenue || 0)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Section: ML Predictions */}
      <h3 style={styles.sectionTitle}>🧠 AI Predictions</h3>

      <div style={styles.predictionsGrid}>
        {/* Revenue Prediction */}
        <div style={{ ...styles.predictionCard, borderLeftColor: colors.primary }}>
          <div style={styles.predictionLabel}>Revenue Forecast (Linear Regression)</div>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px', margin: '15px 0' }}>
            {/* Current Month */}
            <div style={{ padding: '10px', backgroundColor: '#f8f9fa', borderRadius: '8px' }}>
              <small style={styles.predictionSmall}>Current Month</small>
              <div style={{ fontSize: '12px', color: '#666', marginBottom: '8px' }}>
                {monthlyData.length > 0 ? monthlyData[monthlyData.length - 1].month : 'N/A'}
              </div>
              <div style={{ ...styles.predictionValue, color: colors.primary, fontSize: '18px' }}>
                {monthlyData.length > 0 ? formatCurrency(monthlyData[monthlyData.length - 1].revenue) : 'N/A'}
              </div>
            </div>
            {/* Next Month Prediction */}
            <div style={{ padding: '10px', backgroundColor: '#e8f5e9', borderRadius: '8px' }}>
              <small style={styles.predictionSmall}>Next Month Predicted</small>
              <div style={{ fontSize: '12px', color: '#666', marginBottom: '8px' }}>
                {getNextMonth()}
              </div>
              <div style={{ ...styles.predictionValue, color: colors.secondary, fontSize: '18px' }}>
                {data?.predicted_revenue ? formatCurrency(data.predicted_revenue) : 'N/A'}
              </div>
            </div>
          </div>
          <small style={styles.forecastNote}>
            Based on historical monthly revenue trends using Linear Regression algorithm
          </small>
        </div>

        {/* Sales Prediction */}
        <div style={{ ...styles.predictionCard, borderLeftColor: colors.secondary }}>
          <div style={styles.predictionLabel}>Sales Forecast (Random Forest)</div>
          <div style={styles.predictionContentGrid}>
            <div>
              <small style={styles.predictionSmall}>Next Month Predicted Sales</small>
              <div style={{ ...styles.predictionValue, color: colors.primary }}>
                {data?.predicted_sales ? Math.round(data.predicted_sales) : 'N/A'} units
              </div>
            </div>
          </div>
          <small style={styles.forecastNote}>
            Based on historical product demand using Random Forest algorithm
          </small>
        </div>

        {/* Top Brand Prediction */}
        <div style={{ ...styles.predictionCard, borderLeftColor: colors.success }}>
          <div style={styles.predictionLabel}>Top Brand Prediction (Decision Tree)</div>
          <div style={styles.predictionContentGrid}>
            <div>
              <small style={styles.predictionSmall}>Most Likely Top Performing Brand</small>
              <div style={{ ...styles.predictionValue, color: colors.success }}>
                {topBrand}
              </div>
            </div>
          </div>
          <small style={styles.forecastNote}>
            Predicted using Decision Tree classification algorithm
          </small>
        </div>
      </div>

      {/* Detailed Monthly Data Table */}
      <h3 style={styles.sectionTitle}>📋 Detailed Monthly Data</h3>

      <div style={styles.tableContainer}>
        <table style={styles.table}>
          <thead style={styles.tableHead}>
            <tr>
              <th style={styles.tableHeader}>Month</th>
              <th style={styles.tableHeader}>Revenue (₹)</th>
              <th style={styles.tableHeader}>Products Sold</th>
              <th style={styles.tableHeader}>Orders</th>
            </tr>
          </thead>
          <tbody>
            {monthlyData.map((item, idx) => (
              <tr key={idx} style={styles.tableRow}>
                <td style={styles.tableCell}>
                  <strong>{item.month || 'N/A'}</strong>
                </td>
                <td style={styles.tableCell}>{formatCurrency(item.revenue || 0)}</td>
                <td style={styles.tableCell}>{formatNumber(item.products || 0)}</td>
                <td style={styles.tableCell}>
                  <span style={{ ...styles.badge, backgroundColor: colors.primary }}>
                    {formatNumber(item.orders || 0)}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Footer */}
      <div style={styles.footer}>
        <p>
          💡 <strong>ML Models Used:</strong> Linear Regression (Revenue), Random Forest (Demand), Decision Tree (Top
          Brand)
        </p>
        <p style={styles.footerSmall}>
          Data is fetched from MongoDB orders collection. Models trained on historical e-commerce data. All predictions
          are based on machine learning algorithms.
        </p>
      </div>
    </div>
  );
};

